using System.Diagnostics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using TextAnalysis;

// Build the test corpus
var rng = new Random(42);
var sampleWords = new[]
{
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "benchmark", "performance", "analysis", "computation", "algorithm",
    "infrastructure", "extraordinary", "implementation", "documentation",
    "a", "I", "an", "it", "is", "on", "at", "to", "be", "do", "go",
    "internationalization", "characteristically", "disproportionately"
};
var words = new string[10_000];
for (int i = 0; i < words.Length; i++)
    words[i] = sampleWords[rng.Next(sampleWords.Length)];
var analyzer = new TextAnalyzer(string.Join(' ', words));

Console.WriteLine($"Runtime: {RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Words: {analyzer.WordCount:N0}");
Console.WriteLine();

const int warmupIterations = 500;
const int measuredIterations = 5000;

Benchmark("AverageWordLength", () => analyzer.AverageWordLength());
Benchmark("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Benchmark("UniqueWordCount", () => analyzer.UniqueWordCount());

[MethodImpl(MethodImplOptions.NoInlining)]
static void Benchmark(string name, Func<object?> action)
{
    // Warmup
    for (int i = 0; i < warmupIterations; i++)
        action();

    // Collect multiple rounds to compute mean and stddev
    const int rounds = 10;
    int opsPerRound = measuredIterations / rounds;
    double[] roundNs = new double[rounds];
    var sw = new Stopwatch();

    for (int r = 0; r < rounds; r++)
    {
        sw.Restart();
        for (int i = 0; i < opsPerRound; i++)
            action();
        sw.Stop();
        roundNs[r] = (double)sw.Elapsed.TotalNanoseconds / opsPerRound;
    }

    double mean = roundNs.Average();
    double stddev = Math.Sqrt(roundNs.Select(x => (x - mean) * (x - mean)).Average());

    Console.WriteLine($"{name,-25} {mean,10:F1} ns ± {stddev,8:F1} ns  (per op, {measuredIterations} ops, {rounds} rounds)");
}

